package com.example.grpc.error;

import com.google.protobuf.Any;
import io.grpc.Status;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;
import io.grpc.stub.StreamObserver;

import java.io.PrintWriter;
import java.io.StringWriter;
import java.sql.SQLException;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ErrorServiceImpl extends ErrorServiceGrpc.ErrorServiceImplBase {
    private static final Logger logger = Logger.getLogger(ErrorServiceImpl.class.getName());

    @Override
    public void doDangerousOperation(OperationRequest request, StreamObserver<OperationResponse> responseObserver) {
        if (request.getShouldFail()) {
            try {
                String failureType = request.getFailureType();
                switch (failureType) {
                    case "runtime":
                        throw new RuntimeException("Simulated runtime error during operation " + request.getOperationId());
                    case "database":
                        // Simulate a database error
                        throw new SQLException("Database connection lost or query failed for " + request.getOperationId() + ". SQLSTATE: 08006");
                    case "internal_state":
                        // Simulate an error due to invalid internal state
                        if (request.getInternalStateValue().equals("invalid")) {
                            throw new IllegalStateException("Internal state found to be 'invalid' for operation " + request.getOperationId());
                        } else {
                            throw new IllegalArgumentException("Unexpected internal state value: " + request.getInternalStateValue() + " for " + request.getOperationId());
                        }
                    default:
                        throw new IllegalArgumentException("Unknown or unhandled failure type: " + failureType + " for operation " + request.getOperationId());
                }
            } catch (Exception e) {
                logger.log(Level.WARNING, "Operation failed with exception: " + e.getMessage(), e);

                // 1. Capture stack trace
                StringWriter sw = new StringWriter();
                PrintWriter pw = new PrintWriter(sw);
                e.printStackTrace(pw);
                String stackTrace = sw.toString();

                // 2. Build DetailedError custom message
                DetailedError.Builder detailedErrorBuilder = DetailedError.newBuilder()
                        .setErrorCode("APP_FAILURE_001") // Custom application-specific error code
                        .setMessage(e.getMessage())
                        .setStackTrace(stackTrace)
                        .setOperationId(request.getOperationId())
                        .setFailureType(request.getFailureType());

                // Add internal state
                detailedErrorBuilder.putInternalState("request_received_time", String.valueOf(System.currentTimeMillis()));
                detailedErrorBuilder.putInternalState("requested_failure_type", request.getFailureType());
                if (!request.getInternalStateValue().isEmpty()) {
                    detailedErrorBuilder.putInternalState("provided_internal_state_value", request.getInternalStateValue());
                }
                detailedErrorBuilder.putInternalState("server_hostname", "localhost"); // Example internal state

                // Add database error message if applicable
                if (e instanceof SQLException) {
                    detailedErrorBuilder.setDatabaseErrorMessage("SQL Exception details: " + e.getMessage() + ". SQLSTATE: " + ((SQLException) e).getSQLState());
                }

                // 3. Create com.google.rpc.Status (protobuf Status)
                com.google.rpc.Status rpcStatus = com.google.rpc.Status.newBuilder()
                        .setCode(com.google.rpc.Code.INTERNAL.getNumber()) // Standard gRPC status code
                        .setMessage("Operation failed. See details for debugging.") // A generic message for the client
                        .addDetails(Any.pack(detailedErrorBuilder.build())) // Embed our custom DetailedError
                        .build();

                // 4. Convert to io.grpc.StatusRuntimeException
                // This converts the protobuf Status message to a gRPC runtime exception.
                StatusRuntimeException statusRuntimeException = StatusProto.toStatusRuntimeException(
                        rpcStatus,
                        io.grpc.Metadata.EMPTY // You can add custom gRPC headers here if needed
                );

                responseObserver.onError(statusRuntimeException);
            }
        } else {
            // Successful operation
            OperationResponse response = OperationResponse.newBuilder()
                    .setResult("Operation " + request.getOperationId() + " completed successfully.")
                    .build();
            responseObserver.onNext(response);
            responseObserver.onCompleted();
        }
    }
}


