package com.example.grpc.error;

import com.google.protobuf.InvalidProtocolBufferException;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.StatusRuntimeException;
import io.grpc.protobuf.StatusProto;

import java.util.Iterator;
import java.util.concurrent.TimeUnit;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ErrorServiceClient {
    private static final Logger logger = Logger.getLogger(ErrorServiceClient.class.getName());

    private final ManagedChannel channel;
    private final ErrorServiceGrpc.ErrorServiceBlockingStub blockingStub;

    public ErrorServiceClient(String host, int port) {
        channel = ManagedChannelBuilder.forAddress(host, port)
                .usePlaintext() // For development; use secure channels in production
                .build();
        blockingStub = ErrorServiceGrpc.newBlockingStub(channel);
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public void doOperation(String operationId, boolean shouldFail, String failureType, String internalStateValue) {
        OperationRequest request = OperationRequest.newBuilder()
                .setOperationId(operationId)
                .setShouldFail(shouldFail)
                .setFailureType(failureType)
                .setInternalStateValue(internalStateValue)
                .build();

        logger.info(String.format("Attempting operation '%s' (fail: %s, type: %s)", operationId, shouldFail, failureType));

        try {
            OperationResponse response = blockingStub.doDangerousOperation(request);
            logger.info("Operation successful: " + response.getResult());
        } catch (StatusRuntimeException e) {
            logger.log(Level.SEVERE, "Operation failed with gRPC status: " + e.getStatus().getCode() + ", description: " + e.getStatus().getDescription());

            // Try to extract detailed error information
            com.google.rpc.Status status = StatusProto.fromThrowable(e);
            if (status != null) {
                logger.severe("gRPC Status Message: " + status.getMessage());
                logger.severe("gRPC Status Code: " + status.getCode());

                Iterator<com.google.protobuf.Any> detailsIterator = status.getDetailsList().iterator();
                while (detailsIterator.hasNext()) {
                    com.google.protobuf.Any anyDetail = detailsIterator.next();
                    try {
                        if (anyDetail.is(DetailedError.class)) {
                            DetailedError detailedError = anyDetail.unpack(DetailedError.class);
                            logger.severe("\n--- Detailed Error Information ---");
                            logger.severe("  Error Code: " + detailedError.getErrorCode());
                            logger.severe("  Message: " + detailedError.getMessage());
                            logger.severe("  Operation ID: " + detailedError.getOperationId());
                            logger.severe("  Failure Type: " + detailedError.getFailureType());
                            if (!detailedError.getDatabaseErrorMessage().isEmpty()) {
                                logger.severe("  Database Error: " + detailedError.getDatabaseErrorMessage());
                            }
                            if (detailedError.getInternalStateMap().size() > 0) {
                                logger.severe("  Internal State: " + detailedError.getInternalStateMap());
                            }
                            logger.severe("  Stack Trace:\n" + detailedError.getStackTrace());
                            logger.severe("--- End Detailed Error Information ---\n");
                        } else {
                            logger.warning("Found a detail of unknown type: " + anyDetail.getTypeUrl());
                        }
                    } catch (InvalidProtocolBufferException ex) {
                        logger.log(Level.SEVERE, "Failed to unpack error detail Any message.", ex);
                    }
                }
            } else {
                logger.severe("No google.rpc.Status object found in exception details.");
            }
        } catch (Exception e) {
            logger.log(Level.SEVERE, "An unexpected error occurred: " + e.getMessage(), e);
        }
    }

    public static void main(String[] args) throws InterruptedException {
        ErrorServiceClient client = new ErrorServiceClient("localhost", 50051);
        try {
            // Scenario 1: Successful operation
            client.doOperation("OP-001-SUCCESS", false, "none", "");

            // Scenario 2: Simulate runtime error
            client.doOperation("OP-002-RUNTIME", true, "runtime", "");

            // Scenario 3: Simulate database error
            client.doOperation("OP-003-DB", true, "database", "");

            // Scenario 4: Simulate internal state error
            client.doOperation("OP-004-INTERNAL-STATE", true, "internal_state", "invalid");

            // Scenario 5: Simulate unknown failure type (server-side IllegalArgumentException)
            client.doOperation("OP-005-UNKNOWN-TYPE", true, "unknown", "");

        } finally {
            client.shutdown();
        }
    }
}